import { useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import * as THREE from 'three';

interface Point { x: number; y: number; z: number; deviation: number; }

function DeviationCloud({ points, range = [-0.5, 0.5] }: { points: Point[]; range?: [number, number] }) {
  const { positions, colors } = useMemo(() => {
    const positions = new Float32Array(points.length * 3);
    const colors = new Float32Array(points.length * 3);
    const colorLow = new THREE.Color('blue');
    const colorHigh = new THREE.Color('red');
    const tmp = new THREE.Color();
    points.forEach((p, i) => {
      positions[i * 3] = p.x; positions[i * 3 + 1] = p.y; positions[i * 3 + 2] = p.z;
      const t = Math.max(0, Math.min(1, (p.deviation - range[0]) / (range[1] - range[0])));
      tmp.lerpColors(colorLow, colorHigh, t);
      colors[i * 3] = tmp.r; colors[i * 3 + 1] = tmp.g; colors[i * 3 + 2] = tmp.b;
    });
    return { positions, colors };
  }, [points, range]);

  return (
    <points>
      <bufferGeometry>
        <bufferAttribute attach='attributes-position' array={positions} count={points.length} itemSize={3} />
        <bufferAttribute attach='attributes-color' array={colors} count={points.length} itemSize={3} />
      </bufferGeometry>
      <pointsMaterial size={0.002} vertexColors />
    </points>
  );
}

export default function ScanViewer({ points }: { points: Point[] }) {
  return (
    <Canvas camera={{ position: [0, 0, 2], fov: 60 }}>
      <ambientLight />
      <DeviationCloud points={points} />
      <OrbitControls />
    </Canvas>
  );
}
